 1	import type { FC, ReactNode } from 'react';
 2	
 3	import {
 4	  Button,
 5	  ButtonVariant,
 6	  EmptyState,
 7	  EmptyStateActions,
 8	  EmptyStateBody,
 9	  EmptyStateFooter,
10	  EmptyStateHeader,
11	  EmptyStateIcon,
12	} from '@patternfly/react-core';
13	import { PlusCircleIcon } from '@patternfly/react-icons';
14	import { useForkliftTranslation } from '@utils/i18n';
15	
16	type ProjectSelectEmptyStateProps = {
17	  emptyStateMessage?: ReactNode;
18	  onCreate?: () => void;
19	};
20	
21	const ProjectSelectEmptyState: FC<ProjectSelectEmptyStateProps> = ({
22	  emptyStateMessage,
23	  onCreate,
24	}) => {
25	  const { t } = useForkliftTranslation();
26	
27	  if (!emptyStateMessage) {
28	    return null;
29	  }
30	
31	  return (
32	    <EmptyState>
33	      <EmptyStateHeader headingLevel="h6" icon={<EmptyStateIcon icon={PlusCircleIcon} />} />
34	      <EmptyStateBody>{emptyStateMessage}</EmptyStateBody>
35	      {onCreate ? (
36	        <EmptyStateFooter>
37	          <EmptyStateActions>
38	            <Button
39	              variant={ButtonVariant.link}
40	              onClick={onCreate}
41	              data-testid="create-project-button"
42	            >
43	              {t('Create project')}
44	            </Button>
45	          </EmptyStateActions>
46	        </EmptyStateFooter>
47	      ) : null}
48	    </EmptyState>
49	  );
50	};
51	
52	export default ProjectSelectEmptyState;

